import * as stylex from "@stylexjs/stylex";
import { Button } from "@/components/ui/Button/button";
import { Text } from "@/components/ui/Text/text";
import { HStack } from "@/components/ui/Stack/stack";
import type { PropsWithStylex } from "@/utils/stylex.utils";
import { heroStyles } from "./hero-01.styles";

type Cta = {
	label: string;
	handleClick?: () => void;
};

type Props = PropsWithStylex<{
	headline: string;
	subheadline?: string;
	primaryCta?: Cta;
	secondaryCta?: Cta;
	imageSrc?: string;
	imageAlt?: string;
	backgroundVariant?: "default" | "muted" | "accent";
}>;

export function Hero01({
	headline,
	subheadline,
	primaryCta,
	secondaryCta,
	imageSrc,
	imageAlt = "",
	backgroundVariant = "default",
	style,
}: Props) {
	return (
		<section
			{...stylex.props(
				heroStyles.section,
				backgroundVariant === "muted" && heroStyles.muted,
				backgroundVariant === "accent" && heroStyles.accent,
				style,
			)}
		>
			<div {...stylex.props(heroStyles.inner)}>
				<div {...stylex.props(heroStyles.textColumn)}>
					<Text variant="h1" style={heroStyles.headline}>
						{headline}
					</Text>
					{subheadline && (
						<Text variant="body1" style={heroStyles.subheadline}>
							{subheadline}
						</Text>
					)}
					{(primaryCta || secondaryCta) && (
						<HStack gap="small" align="center" wrap>
							{primaryCta && (
								<Button onClick={primaryCta.handleClick} fullWidth>
									{primaryCta.label}
								</Button>
							)}
							{secondaryCta && (
								<Button
									variant="ghost"
									onClick={secondaryCta.handleClick}
									fullWidth
								>
									{secondaryCta.label}
								</Button>
							)}
						</HStack>
					)}
				</div>
				<div {...stylex.props(heroStyles.imageColumn)}>
					{imageSrc ? (
						<img
							src={imageSrc}
							alt={imageAlt}
							{...stylex.props(heroStyles.image)}
						/>
					) : (
						<div {...stylex.props(heroStyles.imagePlaceholder)}>
							<svg
								width="64"
								height="64"
								viewBox="0 0 24 24"
								fill="none"
								stroke="currentColor"
								strokeWidth="1.5"
								strokeLinecap="round"
								strokeLinejoin="round"
								aria-hidden="true"
							>
								<rect x="3" y="3" width="18" height="18" rx="2" ry="2" />
								<circle cx="8.5" cy="8.5" r="1.5" />
								<polyline points="21 15 16 10 5 21" />
							</svg>
						</div>
					)}
				</div>
			</div>
		</section>
	);
}

import * as stylex from "@stylexjs/stylex";
import { theme } from "@/lib/theme/contract.stylex";
import { spacing, mediaQueries } from "@/lib/theme/tokens.stylex";

export const heroStyles = stylex.create({
	section: {
		display: "flex",
		flexDirection: "column",
		alignItems: "center",
		paddingTop: spacing.xxxlarge,
		paddingBottom: spacing.xxxlarge,
		paddingLeft: spacing.medium,
		paddingRight: spacing.medium,
		overflow: "hidden",
	},
	default: {
		backgroundColor: theme.background,
	},
	muted: {
		backgroundColor: theme.backgroundSubtle,
	},
	accent: {
		backgroundColor: theme.primarySubtle,
	},
	inner: {
		display: "flex",
		flexDirection: {
			default: "row",
			[mediaQueries.sm]: "column",
		},
		alignItems: "center",
		gap: {
			default: spacing.xxxlarge,
			[mediaQueries.sm]: spacing.xlarge,
		},
		width: "100%",
		maxWidth: 1200,
		marginLeft: "auto",
		marginRight: "auto",
	},
	textColumn: {
		flex: "1 1 50%",
		display: "flex",
		flexDirection: "column",
		gap: spacing.medium,
	},
	imageColumn: {
		flex: "1 1 50%",
		display: "flex",
		alignItems: "center",
		justifyContent: "center",
	},
	image: {
		width: "100%",
		maxWidth: 540,
		height: "auto",
		borderRadius: theme.borderRadius,
		objectFit: "cover",
	},
	imagePlaceholder: {
		width: "100%",
		maxWidth: 540,
		height: 360,
		borderRadius: theme.borderRadius,
		backgroundColor: theme.surfaceSubtle,
		display: "flex",
		alignItems: "center",
		justifyContent: "center",
		color: theme.contentDisabled,
		fontSize: 48,
	},
	headline: {
		maxWidth: 640,
	},
	subheadline: {
		maxWidth: 560,
	},
	actions: {
		display: "flex",
		flexDirection: "row",
		alignItems: "center",
		gap: spacing.small,
		flexWrap: "wrap",
		marginTop: spacing.small,
		width: {
			[mediaQueries.sm]: "100%",
		},
	},
	actionFullWidth: {
		width: {
			[mediaQueries.sm]: "100%",
		},
	},
});
